183	  private async doGenerateGemini(
184	    options: Parameters<ImageModelV3['doGenerate']>[0],
185	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
186	    const {
187	      prompt,
188	      n,
189	      size,
190	      aspectRatio,
191	      seed,
192	      providerOptions,
193	      headers,
194	      abortSignal,
195	      files,
196	      mask,
197	    } = options;
198	    const warnings: Array<SharedV3Warning> = [];
199	
200	    // Gemini does not support mask-based inpainting
201	    if (mask != null) {
202	      throw new Error(
203	        'Gemini image models do not support mask-based image editing.',
204	      );
205	    }
206	
207	    // Gemini does not support generating multiple images per call via n parameter
208	    if (n != null && n > 1) {
209	      throw new Error(
210	        'Gemini image models do not support generating a set number of images per call. Use n=1 or omit the n parameter.',
211	      );
212	    }
213	
214	    if (size != null) {
215	      warnings.push({
216	        type: 'unsupported',
217	        feature: 'size',
218	        details:
219	          'This model does not support the `size` option. Use `aspectRatio` instead.',
220	      });
221	    }
222	
223	    // Build user message content for language model
224	    const userContent: Array<
225	      | { type: 'text'; text: string }
226	      | { type: 'file'; data: string | Uint8Array | URL; mediaType: string }
227	    > = [];
228	
229	    // Add text prompt
230	    if (prompt != null) {
231	      userContent.push({ type: 'text', text: prompt });
232	    }
233	
234	    // Add input images for editing
235	    if (files != null && files.length > 0) {
236	      for (const file of files) {
237	        if (file.type === 'url') {
238	          userContent.push({
239	            type: 'file',
240	            data: new URL(file.url),
241	            mediaType: 'image/*',
242	          });
243	        } else {
244	          userContent.push({
245	            type: 'file',
246	            data:
247	              typeof file.data === 'string'
248	                ? file.data
249	                : new Uint8Array(file.data),
250	            mediaType: file.mediaType,
251	          });
252	        }
253	      }
254	    }
255	
256	    const languageModelPrompt: LanguageModelV3Prompt = [
257	      { role: 'user', content: userContent },
258	    ];
259	
260	    // Instantiate language model
261	    const languageModel = new GoogleGenerativeAILanguageModel(this.modelId, {
262	      provider: this.config.provider,
263	      baseURL: this.config.baseURL,
264	      headers: this.config.headers ?? {},
265	      fetch: this.config.fetch,
266	      generateId: this.config.generateId ?? defaultGenerateId,
267	    });
268	
269	    // Call language model with image-only response modality
270	    const result = await languageModel.doGenerate({
271	      prompt: languageModelPrompt,
272	      seed,
273	      providerOptions: {
274	        google: {
275	          responseModalities: ['IMAGE'],
276	          imageConfig: aspectRatio
277	            ? {
278	                aspectRatio: aspectRatio as NonNullable<
279	                  GoogleLanguageModelOptions['imageConfig']
280	                >['aspectRatio'],
281	              }
282	            : undefined,
283	          ...((providerOptions?.google as Omit<
284	            GoogleLanguageModelOptions,
285	            'responseModalities' | 'imageConfig'
286	          >) ?? {}),
287	        } satisfies GoogleLanguageModelOptions,
288	      },
289	      headers,
290	      abortSignal,
291	    });
292	
293	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
294	
295	    // Extract images from language model response
296	    const images: string[] = [];
297	    for (const part of result.content) {
298	      if (part.type === 'file' && part.mediaType.startsWith('image/')) {
299	        images.push(convertToBase64(part.data));
300	      }
301	    }
302	
303	    return {
304	      images,
305	      warnings,
306	      providerMetadata: {
307	        google: {
308	          images: images.map(() => ({})),
309	        },
310	      },
311	      response: {
312	        timestamp: currentDate,
313	        modelId: this.modelId,
314	        headers: result.response?.headers,
315	      },
316	      usage: result.usage
317	        ? {
318	            inputTokens: result.usage.inputTokens.total,
319	            outputTokens: result.usage.outputTokens.total,
320	            totalTokens:
321	              (result.usage.inputTokens.total ?? 0) +
322	              (result.usage.outputTokens.total ?? 0),
323	          }
324	        : undefined,
325	    };
326	  }
327	}
