126	            ...(providerOptions?.bedrock?.negativeText
127	              ? { negativeText: providerOptions.bedrock.negativeText }
128	              : {}),
129	            ...(providerOptions?.bedrock?.outPaintingMode
130	              ? { outPaintingMode: providerOptions.bedrock.outPaintingMode }
131	              : {}),
132	          };
