135	          if (hasMask) {
136	            outPaintingParams.maskImage = getBase64Data(mask);
137	          } else if (hasMaskPrompt) {
138	            outPaintingParams.maskPrompt = providerOptions.bedrock.maskPrompt;
139	          }
140	
141	          args = {
142	            taskType: 'OUTPAINTING',
143	            outPaintingParams,
144	            imageGenerationConfig,
145	          };
146	          break;
147	        }
148	
149	        case 'BACKGROUND_REMOVAL': {
150	          // Background removal only needs the image, no other params
151	          args = {
152	            taskType: 'BACKGROUND_REMOVAL',
153	            backgroundRemovalParams: {
