187	          throw new Error(`Unsupported task type: ${taskType}`);
188	      }
189	    } else {
190	      // Standard image generation mode
191	      args = {
192	        taskType: 'TEXT_IMAGE',
193	        textToImageParams: {
194	          text: prompt,
195	          ...(providerOptions?.bedrock?.negativeText
196	            ? {
197	                negativeText: providerOptions.bedrock.negativeText,
198	              }
199	            : {}),
200	          ...(providerOptions?.bedrock?.style
201	            ? {
202	                style: providerOptions.bedrock.style,
