245	      );
246	    }
247	
248	    // Check if images are present
249	    if (!response.images || response.images.length === 0) {
250	      throw new Error(
251	        'Amazon Bedrock returned no images. ' +
252	          (response.status ? `Status: ${response.status}` : ''),
253	      );
254	    }
255	
256	    return {
257	      images: response.images,
258	      warnings,
259	      response: {
260	        timestamp: currentDate,
261	        modelId: this.modelId,
262	        headers: responseHeaders,
263	      },
264	    };
265	  }
266	}
