268	function getBase64Data(file: ImageModelV3File): string {
269	  if (file.type === 'url') {
270	    throw new Error(
271	      'URL-based images are not supported for Amazon Bedrock image editing. ' +
272	        'Please provide the image data directly.',
273	    );
274	  }
275	
276	  if (file.data instanceof Uint8Array) {
277	    return convertUint8ArrayToBase64(file.data);
278	  }
279	
280	  // Already base64 string
281	  return file.data;
282	}
